# railway.env.map — manifest DECLARATIVE: biến nào được push lên service nào.
# Push bằng scripts/railway-sync-env.sh (đọc root .env + manifest này).
# Format:  VAR_NAME  service1,service2
#
# KHÔNG đưa vào đây (script sẽ chặn): DATABASE_URL, REDIS_URL, PORT —
# Railway tự cấp qua fromService/reference (DATABASE_URL ← draw-db).
#
# noddle-draw là anonymous-only + BYOK client-side: mọi biến dưới đây đều
# TUỲ CHỌN — thiếu thì app degrade (AI 503, log ship tắt), không crash.

# — AI pool dùng chung (tuỳ chọn — user tự mang key trong app) —
DATABRICKS_HOST             draw-web
DATABRICKS_TOKEN            draw-web
DATABRICKS_CONFIG_PROFILE   draw-web
DATABRICKS_CLAUDE_ENDPOINT  draw-web

# — CORS cho dev tooling (prod same-origin, thường không cần) —
NODDLE_ALLOWED_ORIGINS      draw-web

# — Object storage S3/R2 cho log shipping (tuỳ chọn) —
S3_ENDPOINT_URL             draw-web
S3_BUCKET                   draw-web
S3_ACCESS_KEY_ID            draw-web
S3_SECRET_ACCESS_KEY        draw-web
S3_REGION                   draw-web
